%[text] # 추가 자료
%[text] 
%[text] ## 체스판
%[text] 
h = 20;
w = 20;

G = ones(h, w, 'int8') * 120;
B = zeros(h, w, 'int8');
C = [G B; B G];

R = repmat(C, 5, 5);
imshow(R)
%%
clear;
h = 20;
w = 20;

odd = uint8(mod(2:11,2));
even = uint8(mod(1:10,2));

A = [odd; even];
B = repmat(A, 5, 1);

K = ones(h, w, 'uint8') * 120;
G = kron(B, K);
imshow(G) %[output:97df69ce]
%%
%[text] ## 흑백 프레임 만들기
%[text] 
clear;

imax = 255;
imin = 50;

h = 20;
w = 20;

n = 10;
bd = [10; 10];

K = ones(h, w, 'uint8');
R = randi([imin , imax], n, 'uint8');
G = randi([imin , imax], n, 'uint8');
B = randi([imin , imax], n, 'uint8');

R1 = kron(R, K);
G1 = kron(G, K);
B1 = kron(B, K);

R1 = padarray(R1, bd, 150);
G1 = padarray(G1, bd, 150);
B1 = padarray(B1, bd, 150);

C = cat(3, R1, G1, B1);
imshow(C) %[output:85a7f684]
%%
%[text] ## 배경 이미지 만들기
%[text] 
clear;

h = 100;
w = 100;

pink   = [255 204 255];
green  = [153, 255, 153];
yellow = [255, 255, 153];
blue   = [204 255 255];

n = 2;

K = ones(n, 'uint8');

PR = ones(h, w, 'uint8') * pink(1); PR = kron(PR, K);
PG = ones(h, w, 'uint8') * pink(2); PG = kron(PG, K);
PB = ones(h, w, 'uint8') * pink(3); PB = kron(PB, K);

GR = ones(h, w, 'uint8') * green(1); GR = kron(GR, K);
GG = ones(h, w, 'uint8') * green(2); GG = kron(GG, K);
GB = ones(h, w, 'uint8') * green(3); GB = kron(GB, K);

YR = ones(h, w, 'uint8') * yellow(1); YR = kron(YR, K);
YG = ones(h, w, 'uint8') * yellow(2); YG = kron(YG, K);
YB = ones(h, w, 'uint8') * yellow(3); YB = kron(YB, K);

BR = ones(h, w, 'uint8') * blue(1); BR = kron(BR, K);
BG = ones(h, w, 'uint8') * blue(2); BG = kron(BG, K);
BB = ones(h, w, 'uint8') * blue(3); BB = kron(BB, K);

CP = cat(3, PR, PG, PB);
CG = cat(3, GR, GG, GB);
CY = cat(3, YR, YG, YB);
CB = cat(3, BR, BG, BB);

Result = [CP CG; CY CB];

gh = 400;
gw = 400;

[X, Y] = meshgrid(-gw/2:gw/2-1, gh/2-1:-1:-gh/2);

Z = X.^2 + Y.^2;

M = (Z <= 160^2) & (Z >= 100^2);

MR = uint8(153 * M);
MG = uint8(102 * M);
MB = uint8( 51 * M);

C = cat(3, MR, MG, MB);

Combined = Result;

Combined(:,:,1) = uint8(~M).*Result(:,:,1) + uint8(M).*C(:,:,1);
Combined(:,:,2) = uint8(~M).*Result(:,:,2) + uint8(M).*C(:,:,2);
Combined(:,:,3) = uint8(~M).*Result(:,:,3) + uint8(M).*C(:,:,3);

figure; %[output:059a91c3]
imshow(Combined); %[output:059a91c3]
clear;
h = 160;
w = 160;

bd = [20 20];

g = [0 255 0];

A = uint8(ones(h, w) * 255);
B = uint8(ones(h, w) * 255);
C = uint8(ones(h, w) * 255);

AR = padarray(A, bd, g(1));
AG = padarray(B, bd, g(2));
AB = padarray(C, bd, g(3));

G = cat(3, AR, AG, AB);
imshow(G) %[output:50fa89ce]
%%
% 팔레트의 컬러값
R = [218 255 255 199 144  88];
G = [247 195  87   0  12  24];
B = [166   0  51  57  63  69];
% 이미지 C를 만들고 palette.png파일에 저장하시오.
% 여러분의 코드는 여기부터 시작하며, R, G, B값을 이용하여야 합니다.
h = 100;
w = 150;

greenr = ones(h, w, 'uint8') * R(1); 
greeng = ones(h, w, 'uint8') * G(1);
greenb = ones(h, w, 'uint8') * B(1);
green = cat(3, greenr, greeng, greenb);

yellowr = ones(h, w, 'uint8') * R(2); 
yellowg = ones(h, w, 'uint8') * G(2);
yellowb = ones(h, w, 'uint8') * B(2);
yellow = cat(3, yellowr, yellowg, yellowb);

orranger = ones(h, w, 'uint8') * R(3);
orrangeg = ones(h, w, 'uint8') * G(3);
orrangeb = ones(h, w, 'uint8') * B(3);
orrange = cat(3, orranger, orrangeg, orrangeb);

redr = ones(h, w, 'uint8') * R(4);
redg = ones(h, w, 'uint8') * G(4);
redb = ones(h, w, 'uint8') * B(4);
red = cat(3, redr, redg, redb);

dredr = ones(h, w, 'uint8') * R(5);
dredg = ones(h, w, 'uint8') * G(5);
dredb = ones(h, w, 'uint8') * B(5);
dred = cat(3, dredr, dredg, dredb);

purpler = ones(h, w, 'uint8') * R(6);
purpleg = ones(h, w, 'uint8') * G(6);
purpleb = ones(h, w, 'uint8') * B(6);
purple = cat(3, purpler, purpleg, purpleb);

C = [green yellow orrange red dred purple];
imshow(C); %[output:07ba004d]
imwrite(C, 'palette.png')
%[text] 
%%
% 팔레트의 컬러값
R = [218 255 255 199 144  88];
G = [247 195  87   0  12  24];
B = [166   0  51  57  63  69];
% 이미지 C를 만들고 palette.png파일에 저장하시오.
% 여러분의 코드는 여기부터 시작하며, R, G, B값을 이용하여야 합니다.
h = 1;
w = 15;

A = ones(h, w)
%[text] 
%%
% 우선 빈 이미지를 생성합니다.
C = 255 * ones(800,800,3,'uint8');
% meshgrid()를 이용하여 800x800에 대한 좌표를 생성합니다.
x = linspace(-4, 4, 800);
[X, Y] = meshgrid(x);
% 이제 생성된 좌표값을 활용하여 C 값을 설정합니다.
Z = X.^2 -Y.^2;
Z1 = X + Y;
Z2 = X - Y;

M1 = Z >= 1;
M2 = Z < 1;
M3 = Z1 == 0 & Z2 == 0 ;


R = ones(800, 800, 'uint8');
G = R;
B = R;

R(M1) = 255;
G(M1) = 255;
B(M1) = 0;

R(M2) = 255;
G(M2) = 0;
B(M2) = 255;

R() = 255;
G() = 255;
B() = 255;

C = cat(3, R, G, B);
% 완성된 이미지를 보여줍니다.
imshow(C); %[output:6c07f108]

